/* IvaBot SEO Tools v7.6 */
(function(){
  function b64decode(str){
    var bin=atob(str);
    var bytes=new Uint8Array(bin.length);
    for(var i=0;i<bin.length;i++)bytes[i]=bin.charCodeAt(i);
    return new TextDecoder('utf-8').decode(bytes);
  }
  function boot(){
    if(typeof React==='undefined'||typeof ReactDOM==='undefined'||typeof Babel==='undefined'){
      setTimeout(boot,100);return;
    }
    var code=b64decode('');
    code+='\nReactDOM.createRoot(document.getElementById("ivabot-root")).render(React.createElement(IvaBotApp));';
    try{
      var transpiled=Babel.transform(code,{presets:['react']}).code;
      var fn=new Function(transpiled);
      fn();
    }catch(e){
      console.error('IvaBot init error:',e);
      document.getElementById('ivabot-root').innerHTML='<div style="padding:40px;text-align:center;color:#928E95;font-family:DM Sans,sans-serif">Loading error. Check console.</div>';
    }
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',boot)}else{boot()}
})();
